-- Sepsis
update public.articles
set content = '{"schemaVersion": 2, "sections": [{"key": "definition", "body": "Life-threatening organ dysfunction caused by a dysregulated host response to infection."}, {"key": "epidemiology", "body": "Leading cause of mortality in Ethiopian ICU settings; high burden in post-operative patients."}, {"key": "etiology", "body": "Bacterial (Gram-negative most common), Viral (COVID-19), or Fungal."}, {"key": "pathophysiology", "body": "Systemic inflammation → endothelial damage → capillary leak → tissue hypoxia → multi-organ failure."}, {"key": "clinicalFeatures", "body": "Fever/hypothermia, tachycardia, tachypnea, altered mental status, MAP < 65 mmHg."}, {"key": "diagnosis", "body": "qSOFA score, Lactate > 2 mmol/L, Blood cultures, CBC (leukocytosis/leukopenia)."}, {"key": "treatment", "body": "Aggressive fluid resuscitation (30ml/kg), broad-spectrum antibiotics (Ceftriaxone + Metronidazole) within 1 hour."}, {"key": "complications", "body": "Septic shock, ARDS, Acute Kidney Injury (AKI), DIC."}, {"key": "ethiopianContext", "body": "Management limited by oxygen and ICU bed scarcity. Focus on early identification and fluid resuscitation at district level."}, {"key": "mnemonics", "body": "TIME: Temperature, Infection, Mental status, Extremely ill."}]}'::jsonb
where id = 'e44f7b04-fff9-4a20-8c43-eaf2fb760ae8';

