-- Neonatal Sepsis
update public.articles
set content = '{"schemaVersion": 2, "sections": [{"key": "definition", "body": "A clinical syndrome characterized by systemic signs and symptoms of infection in the first 28 days of life."}, {"key": "epidemiology", "body": "High incidence in low-resource settings."}, {"key": "etiology", "body": "**Causes:** E. coli, Klebsiella."}, {"key": "pathophysiology", "body": "Systemic inflammation and MODS."}, {"key": "clinicalFeatures", "body": "**Signs:** Temp instability, poor feeding."}, {"key": "diagnosis", "body": "**Gold Standard:** Blood Culture."}, {"key": "treatment", "body": "**MoH:** Ampicillin and Gentamicin."}, {"key": "complications", "body": "Septic shock, meningitis."}, {"key": "ethiopianContext", "body": "Focus on IMNCI danger signs and C5 aseptic delivery."}, {"key": "mnemonics", "body": "C5 Aseptic Delivery"}]}'::jsonb
where id = 'b470a782-22d7-49df-aac2-e77c06048a3b';

-- Pleural Effusion
update public.articles
set content = '{"schemaVersion": 2, "sections": [{"key": "definition", "body": "Abnormal accumulation of fluid in the pleural space."}, {"key": "epidemiology", "body": "Commonly secondary to TB or Heart Failure in Ethiopia."}, {"key": "pathophysiology", "body": "Increased hydrostatic pressure (Heart Failure) or increased permeability (Infection/TB)."}, {"key": "clinicalFeatures", "body": "Dyspnea, pleuritic pain, decreased breath sounds, stony dull percussion."}, {"key": "diagnosis", "body": "Chest X-ray (blunting of costophrenic angle), Thoracentesis (fluid analysis)."}, {"key": "treatment", "body": "Drainage (Thoracentesis), treat underlying cause."}, {"key": "complications", "body": "Empyema, lung collapse."}]}'::jsonb
where id = 'dc6dc539-928d-4c38-8224-4888232b61a7';

-- Tension Pneumothorax
update public.articles
set content = '{"schemaVersion": 2, "sections": [{"key": "definition", "body": "Life-threatening collection of air in the pleural space that cannot escape."}, {"key": "pathophysiology", "body": "One-way valve mechanism → air enters on inspiration → intrapleural pressure rises → mediastinal shift."}, {"key": "clinicalFeatures", "body": "Sudden dyspnea, tracheal deviation (away from side), hypotension."}, {"key": "diagnosis", "body": "Clinical diagnosis (DO NOT wait for X-ray!)."}, {"key": "treatment", "body": "Immediate needle decompression (2nd ICS) followed by chest tube."}, {"key": "complications", "body": "Cardiac arrest, death."}]}'::jsonb
where id = '35a24bca-d7a3-4480-ba12-e4bfb3bdde13';

-- Tuberculosis (TB)
update public.articles
set content = '{"schemaVersion": 2, "sections": [{"key": "definition", "body": "Chronic bacterial infection."}, {"key": "epidemiology", "body": "Ethiopia is a high-burden country."}, {"key": "etiology", "body": "M. tuberculosis."}, {"key": "pathophysiology", "body": "Granuloma formation."}, {"key": "clinicalFeatures", "body": "Cough >2 weeks, night sweats."}, {"key": "diagnosis", "body": "GeneXpert, Sputum smear."}, {"key": "treatment", "body": "RHZE regimen."}, {"key": "complications", "body": "Miliary TB."}]}'::jsonb
where id = 'a4ef20d4-ed98-4ce5-bb2e-9f996f2e733b';

-- Cholera
update public.articles
set content = '{"schemaVersion": 2, "sections": [{"key": "definition", "body": "Acute diarrheal infection caused by ingestion of food or water contaminated with Vibrio cholerae."}, {"key": "epidemiology", "body": "Frequent outbreaks in Ethiopia, especially during rainy seasons and in refugee/crowded settings."}, {"key": "etiology", "body": "Vibrio cholerae (serogroups O1 and O139)."}, {"key": "pathophysiology", "body": "Cholera toxin → increases cAMP in intestinal cells → massive secretion of water and electrolytes into lumen."}, {"key": "clinicalFeatures", "body": "Profuse ''rice-water'' stool, vomiting, rapid dehydration, muscle cramps."}, {"key": "diagnosis", "body": "Stool culture (TCBS agar), Rapid Diagnostic Tests (RDT) during outbreaks."}, {"key": "treatment", "body": "Aggressive rehydration (ORS or IV Ringers Lactate), Zinc supplementation, Antibiotics (Doxycycline or Azithromycin) to shorten duration."}, {"key": "complications", "body": "Severe dehydration, Hypovolemic shock, Hypokalemia, Death within hours."}, {"key": "ethiopianContext", "body": "National guidelines prioritize Oral Rehydration Points (ORP) and strict isolation in Cholera Treatment Centers (CTC)."}]}'::jsonb
where id = '545cd76e-59ae-4579-8778-b8ab7b65de5b';

-- Peptic Ulcer Disease (PUD)
update public.articles
set content = '{"schemaVersion": 2, "sections": [{"key": "definition", "body": "Breach in the mucosal lining of the stomach or duodenum."}, {"key": "epidemiology", "body": "Very common; H. pylori is the leading cause in Ethiopia."}, {"key": "etiology", "body": "H. pylori infection, NSAID use, smoking."}, {"key": "clinicalFeatures", "body": "Epigastric pain (burning), dyspepsia, pain relieved/worsened by food."}, {"key": "diagnosis", "body": "Endoscopy (gold standard), H. pylori breath/stool test."}, {"key": "treatment", "body": "Triple therapy (PPI + Clarithromycin + Amoxicillin)."}, {"key": "complications", "body": "Perforation, GI bleeding (hematemesis/melena)."}]}'::jsonb
where id = '3ece5cf5-e744-468b-b109-d42afce3e446';

-- Liver Cirrhosis
update public.articles
set content = '{"schemaVersion": 2, "sections": [{"key": "definition", "body": "Late-stage fibrosis (scarring) of the liver caused by chronic liver disease."}, {"key": "epidemiology", "body": "Common in Ethiopia due to Hepatitis B and chronic alcohol use."}, {"key": "pathophysiology", "body": "Chronic injury → stellate cell activation → collagen deposition → nodular regeneration."}, {"key": "clinicalFeatures", "body": "Jaundice, ascites, spider angiomata, caput medusae."}, {"key": "diagnosis", "body": "Ultrasound, Liver function tests (↑AST/ALT, ↓Albumin), Biopsy."}, {"key": "treatment", "body": "Treat cause, diuretics for ascites, lactulose for encephalopathy."}, {"key": "complications", "body": "HCC (Cancer), Variceal bleeding."}]}'::jsonb
where id = '69e24789-896d-4bc5-81c8-3eea4fc5863e';

-- Hepatitis B
update public.articles
set content = '{"schemaVersion": 2, "sections": [{"key": "definition", "body": "Viral infection that attacks the liver and can cause both acute and chronic disease."}, {"key": "epidemiology", "body": "Highly endemic in Ethiopia; vertical transmission is common."}, {"key": "pathophysiology", "body": "Hepatocyte damage caused by the host immune response against the virus."}, {"key": "clinicalFeatures", "body": "Fever, fatigue, jaundice, dark urine, RUQ pain."}, {"key": "diagnosis", "body": "Serology (HBsAg, Anti-HBc, HBeAg)."}, {"key": "treatment", "body": "Antivirals (Tenofovir/Entecavir) if chronic; supportive if acute."}, {"key": "complications", "body": "Cirrhosis, Hepatocellular carcinoma."}]}'::jsonb
where id = 'd69eade1-179f-4208-887a-7d466351f844';

-- Hyperthyroidism
update public.articles
set content = '{"schemaVersion": 2, "sections": [{"key": "definition", "body": "Condition caused by excessive production of thyroid hormones."}, {"key": "etiology", "body": "Graves’ disease (toxic diffuse goiter), Toxic multinodular goiter."}, {"key": "clinicalFeatures", "body": "Tachycardia, weight loss, heat intolerance, tremors, exophthalmos (Graves)."}, {"key": "diagnosis", "body": "↓ TSH, ↑ Free T4."}, {"key": "treatment", "body": "Anti-thyroid drugs (Methimazole/PTU), Beta-blockers (for symptoms), Surgery."}, {"key": "complications", "body": "Thyroid storm, atrial fibrillation."}]}'::jsonb
where id = 'dbe37027-8f87-4fbe-97a3-498add8fc45b';
